  const d = min(dXY, distZ);

  const hi = add(thickness, 0.01);
  const k = smoothstep(thickness, hi, d);

  const lineColor = color(0x1A1A1A);
  const bgColor = color(0xF2F2F2);
  const result = mix(lineColor, bgColor, k);
