  const k = add(stripeNoise, stripeShift);
  const negBlur = mul(blur, -1);
  const stripes = smoothstep(negBlur, blur, k);
  const pattern = oneMinus(stripes);

  const bellyT = smoothstep(-1, 0.5, pos.y);

  const furColor = color(0xFFAB00);
